INSERT INTO plans VALUES(449,1,445,'Plan: Markdown AST to Templ Components','Detailed implementation plan for building a goldmark AST to templ component renderer. Covers architecture, section grouping, collapsible headings via Alpine.js, styling, and phased implementation.',X'',NULL,'now','verify','/Users/mikeschinkel/.claude/plans/abundant-wiggling-pearl.md',0,'2026-04-14T06:14:53',NULL);
INSERT INTO plans VALUES(496,1,444,'Show pending children of completed parents in plan tree','The plan tree currently hides all children of completed parents. But a pending TODO under a completed parent should still be visible — otherwise work gets lost when a parent is marked done before all follow-on tasks are captured as their own plans.',NULL,NULL,'now','needs_plan',NULL,80,'2026-04-14T06:23:04',NULL);
INSERT INTO plans VALUES(497,1,445,'Clean up Markdown Component plan: collapse auto-parsed items into single record','The spawned Markdown Component session used plan import which auto-parsed its plan into 46 items in a deep hierarchy. That plan should be one atomic record under #445, not a tree of implementation steps. Delete the auto-parsed items and store the plan as a single record with the full text.',NULL,NULL,'now','completed',NULL,90,'2026-04-14T06:23:04','2026-04-14T07:14:25');
INSERT INTO plans VALUES(498,1,444,'Fix hook: read @endless_plan_id from tmux, auto-parent plans on import','The Claude Code hook (cmd/endless-hook/claude.go) needs to read @endless_plan_id from the tmux window option set by endless spawn. When a spawned session writes a plan file or exits plan mode, the hook should auto-parent the import under that plan ID instead of creating a floating root. This also covers wiring up the ExitPlanMode event to trigger import instead of PostToolUse/Write.',NULL,NULL,'now','completed',NULL,100,'2026-04-14T06:23:04','2026-04-14T06:28:01');
INSERT INTO plans VALUES(499,1,444,'Add --description flag to plan add command','The plan add command takes a text argument used as both title and description. Need a separate --description flag so plans can have a short title and a longer description without resorting to SQL.',NULL,NULL,'now','completed',NULL,110,'2026-04-14T06:28:01','2026-04-14T06:37:35');
INSERT INTO plans VALUES(500,1,444,'Track plan file path on ai_sessions during PostToolUse/Write','When the hook sees a Write to ~/.claude/plans/*.md in PostToolUse, record the file path on the ai_sessions row (new column plan_file_path). On ExitPlanMode, read it back to know exactly which file to import. Eliminates the fragile most-recently-modified scan.',NULL,NULL,'now','completed',NULL,120,'2026-04-14T06:35:32','2026-04-14T06:44:20');
INSERT INTO plans VALUES(501,1,444,'Inject plan management instructions via hook additionalContext','Use the hook additionalContext on success responses to remind Claude to create subplans for discovered issues, track the active plan ID, and follow plan management conventions. This is how Endless teaches Claude its workflow without requiring CLAUDE.md changes.',NULL,NULL,'now','needs_plan',NULL,130,'2026-04-14T06:35:32',NULL);
INSERT INTO plans VALUES(502,1,444,'Hook trigger system: regex patterns and user keywords inject context','Two parts: (1) User keywords like RECORD SUBPLAN in UserPromptSubmit trigger additionalContext telling Claude to create a subplan. Deterministic, low false-positive, immediately useful. (2) Regex patterns discovered by analyzing existing hook activity logs — months of data available. Scan tool inputs in PostToolUse for patterns like TODO/FIXME/needs-subplan and nudge Claude. Start with user keywords, add regex triggers after log analysis.',NULL,NULL,'now','needs_plan',NULL,140,'2026-04-14T06:42:09',NULL);
INSERT INTO plans VALUES(503,1,444,'Document CLI commands in README.md','The README needs up-to-date documentation of all endless CLI commands with their current flags and usage. This is the user-facing reference for how to use the tool. Should reflect the current state after all recent changes (plans table, --parent, --description, spawn, detail, prompt).',NULL,NULL,'now','completed',NULL,150,'2026-04-14T06:49:19','2026-04-14T06:50:27');
INSERT INTO plans VALUES(504,1,444,'Create Research Prompt: Beads Comparison','Understand how Endless and Beads overlap and differ. Beads is a project/context management tool that may have similar goals. Need a detailed comparison to inform Endless design decisions.',NULL,NULL,'now','completed',NULL,160,'2026-04-14T19:21:00',NULL);
INSERT INTO plans VALUES(505,1,444,'Plan status icons in dashboard tree','Add colored 3D sphere icons before each plan title in the dashboard tree to visually distinguish status: green=ready, yellow=needs_plan, amber=in_progress, red=blocked, gray=pending. Update schema CHECK constraint, add CSS spheres in status_detail.templ, set correct statuses on existing plans.',NULL,NULL,'now','completed',NULL,170,'2026-04-14T23:33:25','2026-04-14T23:35:56');
INSERT INTO plans VALUES(506,1,443,'Status sphere on every node','Every plan node needs a status sphere — currently missing on parents like Implement Endless and Research. The sphere is the primary visual indicator.',NULL,NULL,'now','completed',NULL,180,'2026-04-14T23:58:43','2026-04-15T00:19:49');
INSERT INTO plans VALUES(507,1,516,'Sort plans by status priority','Default display order: in_progress, ready, needs_plan, blocked, pending. User can override via drag-and-drop (separate plan).',NULL,NULL,'now','completed',NULL,190,'2026-04-14T23:58:43','2026-04-17T06:48:16');
INSERT INTO plans VALUES(508,1,516,'Drag-and-drop reorder','Allow user to drag plans to reorder. Needs HTMX endpoint to persist sort_order. User drags needs_plan to top to signal priority.',NULL,NULL,'now','needs_plan',NULL,200,'2026-04-14T23:58:43',NULL);
INSERT INTO plans VALUES(509,1,516,'Caret-only expand/collapse','Only caret click toggles expand/collapse, not title click. Fix broken Expand/Collapse all links. Title click selects item for detail pane.',unistr('# Plan #509: Caret-Only Expand/Collapse\u000a\u000a## Context\u000a\u000aCurrently, clicking anywhere on a plan item row triggers an action. On the status page, clicking the row toggles the detail pane — the caret button uses `.stop` to prevent this, but the title, status sphere, and phase badge all incorrectly trigger detail toggle. On the plan detail page, clicking anywhere on the row toggles expand/collapse — the caret is just a passive text indicator, not a button.\u000a\u000aThe goal: only the caret toggles expand/collapse. Title click selects the item for the detail pane (status page) or does nothing (plan detail page, until #510 adds editing).\u000a\u000a## Changes\u000a\u000a### status_detail.templ\u000a\u000a**Row div (line 242-243):** Remove `x-on:click` and `cursor-pointer` from the row div. The row should just be a flex container, not a click target.\u000a\u000a**Title span (line 255-257):** Add `x-on:click` to toggle the detail pane. Add `cursor-pointer` to the title span. This makes only the title clickable for detail selection.\u000a\u000a**Caret button (line 245):** Already correct — has `x-on:click.stop` for expand/collapse. Remove the `.stop` modifier since the row no longer has a click handler. Keep `cursor-pointer`.\u000a\u000a**Expand/Collapse all buttons (lines 227-230):** Test whether these work. If broken, likely because `Object.keys()` returns string keys while the template injects numeric IDs. Fix by ensuring consistent key types in `toggleAll()`.\u000a\u000a### plan_detail.templ\u000a\u000a**Row div (line 49):** Remove `x-on:click="open = !open"` and `cursor-pointer` from the row div.\u000a\u000a**Caret indicator (line 61):** Convert from passive `<span>` to clickable `<button>` with `x-on:click="open = !open"` and `cursor-pointer`. Style to match the status page caret pattern.\u000a\u000a**Title span (line 51-53):** No click handler for now — future #510 will add double-click-to-edit.\u000a\u000a## Files Modified\u000a\u000a| File | Change |\u000a|------|--------|\u000a| `internal/web/pages/status_detail.templ` | Move click handlers from row to specific elements |\u000a| `internal/web/pages/plan_detail.templ` | Convert caret to button, remove row-level click |\u000a\u000a## Verification\u000a\u000a- `just build`\u000a- Start dashboard, navigate to `/status/endless`\u000a- Click caret → children expand/collapse\u000a- Click title → detail pane toggles\u000a- Click status sphere or phase badge → nothing happens\u000a- Expand/Collapse all buttons work\u000a- Navigate to `/project/endless/plan`\u000a- Click caret → content expands/collapses\u000a- Click title → nothing happens\u000a- Click status icon → nothing happens\u000a'),NULL,'now','completed',NULL,210,'2026-04-14T23:58:43','2026-04-16 03:14:52');
INSERT INTO plans VALUES(510,1,516,'Double-click title to edit inline','Double-click switches to editable input field (templUI Input component). Save on blur or Enter via HTMX. Lets user reword titles without CLI.',unistr('# Plan #510: Double-Click Title to Edit Inline\u000a\u000a## Original Plan\u000a\u000aThe initial plan assumed pre-#509 state where the entire row was clickable. It proposed a click-timer pattern to disambiguate single-click (toggle detail) from double-click (edit), templUI Input component for the field, and blur-to-save behavior.\u000a\u000a## Implementation Record\u000a\u000a### What was built\u000a\u000aDouble-click on a plan item title opens a floating overlay edit form. The overlay appears at the same X/Y position as the title text, on a higher z-index so the tree layout is undisturbed.\u000a\u000a### Key decisions made during implementation\u000a\u000a1. **No click-timer needed** — After #509 (caret-only expand/collapse), the title span has no single-click handler, so double-click is unambiguous.\u000a\u000a2. **Status sphere toggles detail pane** — User chose this over title-click or caret-both when asked how to trigger the detail pane after removing the row-level click handler.\u000a\u000a3. **Overlay modal, not inline expansion** — Inline editing pushed the tree layout down, misaligning status sphere icons. User requested the form float on top of the existing layout at the title''s position.\u000a\u000a4. **Plain HTML, not templUI Input/Button** — templUI''s Input wraps in `<div class="relative w-full">` which broke overlay sizing. Button variants use CSS theme vars (`bg-primary`) that didn''t render in our dark theme. Plain HTML with explicit Tailwind classes gives full control for this use case.\u000a\u000a5. **Save/Cancel buttons, not blur-to-save** — User wanted visible affordance that editing is happening. Buttons below-right aligned under the field. Green Save (`bg-emerald-600`), gray Cancel (`bg-gray-700`).\u000a\u000a6. **Fixed-width input** — Field size set once on edit start based on title length. Does not grow as user types.\u000a\u000a7. **Alpine x-data methods** — Refactored inline JS chains into named methods (`startEdit`, `saveEdit`, `cancelEdit`). Status page uses a Go helper `planTreeXData()` to build the x-data string. Recorded as completed #621.\u000a\u000a### Files modified\u000a\u000a- `internal/web/queries.go` — Added `UpdatePlanItemTitle()`\u000a- `internal/web/handlers.go` — Added `handleUpdatePlanItemTitle()` PUT handler\u000a- `internal/web/server.go` — Added `PUT /plan-item/{id}/title` route\u000a- `internal/web/pages/status_detail.templ` — Overlay edit form, `planTreeXData()` helper\u000a- `internal/web/pages/plan_detail.templ` — Same overlay pattern, per-item x-data\u000a\u000a# Bugfix: saveEdit updated wrong element (2026-04-17)\u000a\u000aAfter #511 (hover ID) added a `<span>` between the title and the edit overlay, `saveEdit`''s DOM traversal (`el.closest(''.absolute'').previousElementSibling`) found the ID span instead of the title span. Editing would replace the hover ID text with the new title instead of updating the actual title.\u000a\u000a**Fix**: Target title spans directly by ID (`document.getElementById(''title-'' + id)` on status page, `x-ref="titleSpan"` on plan detail page) instead of fragile sibling traversal.\u000a\u000a**Lesson**: DOM traversal via `previousElementSibling`/`closest` is fragile when the template structure changes. Use explicit IDs or refs for elements that need programmatic updates.\u000a'),NULL,'now','completed',NULL,220,'2026-04-14T23:58:43','2026-04-16T06:20:47');
INSERT INTO plans VALUES(511,1,516,'Show plan ID on hover in bright green','Plan IDs are how the user communicates with the AI about specific plans. Show #ID on hover in bright green, not invisible gray.',NULL,NULL,'now','completed',NULL,230,'2026-04-14T23:58:43','2026-04-17T05:58:33');
INSERT INTO plans VALUES(512,1,444,'Refactor detail pages: Alpine.js collapse → templUI collapsible','Replace raw Alpine.js x-data/x-show expand/collapse patterns in plan_detail.templ, status_detail.templ, and project_detail.templ with templUI collapsible components. Ensures consistency with the new markdown component and the rest of the templUI-based UI. Scope: only the expand/collapse toggles, not other Alpine.js usage (theme, filtering).',NULL,NULL,'now','needs_plan',NULL,240,'2026-04-15T00:11:11',NULL);
INSERT INTO plans VALUES(513,1,444,'Syntax highlighting for fenced code blocks','Add syntax highlighting to the markdown AST renderer''s fenced code blocks. Evaluate chroma or goldmark-highlighting extension. Should integrate with the dark theme color palette. Immediate follow-up to the AST-to-templ markdown renderer.',NULL,NULL,'now','needs_plan',NULL,250,'2026-04-15T00:15:55',NULL);
INSERT INTO plans VALUES(514,1,444,'endless plan update command','General-purpose update command: endless plan update <id> --status <status> --title <title> --description <text> --text <file> --prompt <file>. Replaces the need for separate set-status, set-title, etc. commands. The ID is the only positional arg, everything else is flags. Covers changing status (ready, needs_plan, blocked, etc.), updating title/description, loading full plan text from a file, and loading prompts from a file.',NULL,NULL,'now','completed',NULL,260,'2026-04-15T01:21:40','2026-04-15T01:27:34');
INSERT INTO plans VALUES(515,1,444,'Spawned sessions update plan record instead of importing hierarchy','The prompt stored on plans with prompts tells the spawned session to run plan import which auto-parses into a hierarchy. With plans-as-atomic-records, the spawned session should instead update the existing record text field with the full plan content. Needs the plan update command (#513) and a change to how spawn prompts instruct the session to write back.',NULL,NULL,'now','completed',NULL,270,'2026-04-15T01:21:40','2026-04-17T19:04:08');
INSERT INTO plans VALUES(516,1,444,'Status Page Tweaks','Incremental improvements to the existing proof-of-concept status page. These are concrete, implementable changes — unlike the Status Page Deep Dive which is a future design effort.',NULL,NULL,'now','in_progress',NULL,280,'2026-04-15T02:10:17',NULL);
INSERT INTO plans VALUES(517,1,516,'Tooltip on status sphere icons','Each colored sphere needs a tooltip showing the status name (e.g. ''Needs plan'', ''Ready'', ''In progress'', ''Verify'', ''Blocked''). Tooltips may be sufficient instead of a legend — evaluate after implementing.',NULL,NULL,'now','completed',NULL,290,'2026-04-15T02:29:49','2026-04-17T06:37:18');
INSERT INTO plans VALUES(518,1,444,'Hook auto-sets plan status for spawned sessions','When a spawned session starts (SessionStart event), the hook reads @endless_plan_id from tmux and automatically runs endless plan update <id> --status in_progress. On ExitPlanMode or session end, it sets status to verify. This eliminates the need for the spawned session to manually update its own status. Depends on #448 (hook reads tmux metadata) which is implemented but the auto-status behavior is not.',NULL,NULL,'now','needs_plan',NULL,300,'2026-04-15T02:30:07',NULL);
INSERT INTO plans VALUES(519,1,516,'Display plan text column in dashboard detail pane','The plans table has a text column for full plan content (e.g. #449 has 8KB of plan text). The dashboard detail pane only shows the description column. Need to surface the text column — probably as an expandable section below the description, or as a tab/toggle between description and full plan.',NULL,NULL,'now','needs_plan',NULL,310,'2026-04-15T02:30:07',NULL);
INSERT INTO plans VALUES(520,1,444,'Auto-hoist pending children when parent enters verify or complete','When a plan status changes to verify or completed, any children that are not themselves verify or completed should be hoisted to the parent''s parent. This prevents work items from being hidden under a completed parent. Could be enforced in the plan update command or as a hook behavior.',NULL,NULL,'now','needs_plan',NULL,320,'2026-04-15T02:30:07',NULL);
INSERT INTO plans VALUES(571,1,444,'Add "revisit" status to plan lifecycle','Plans that have been partially planned but need re-evaluation after a prerequisite is done. Add revisit to the status enum, update statusLabel/statusSphereClass in the web layer, and handle it in the enforcement hook (treat like needs_plan).',NULL,NULL,'now','needs_plan',NULL,330,'2026-04-15T18:36:32',NULL);
INSERT INTO plans VALUES(572,1,444,'Rename task_dependencies → plan_dependencies','The table task_dependencies and its type values (''task'', ''project'') use stale vocabulary. Rename table to plan_dependencies, change type value ''task'' to ''plan''. Update all references in schema.sql, queries.go, Go monitor code, and Python CLI.',NULL,NULL,'now','needs_plan',NULL,340,'2026-04-15T18:36:32',NULL);
INSERT INTO plans VALUES(573,1,444,'CLI: endless plan add','Add a single plan item from the command line without importing a markdown file. Accepts title, optional description, optional parent ID, optional phase. Example: endless plan add --parent 444 --phase now "My new item"',NULL,NULL,'now','completed',NULL,350,'2026-04-15T18:37:49','2026-04-16 03:42:30');
INSERT INTO plans VALUES(574,1,444,'CLI: endless plan set','Update fields on an existing plan item. Accepts plan ID and key=value pairs for status, title, text, description, phase. Example: endless plan set 510 status=revisit title="New title"',NULL,NULL,'now','completed',NULL,360,'2026-04-15T18:37:49','2026-04-16 03:42:30');
INSERT INTO plans VALUES(575,1,444,'CLI: endless plan dep','Add/remove dependencies between plan items. Example: endless plan dep 510 --needs 509, endless plan dep 510 --remove 509',NULL,NULL,'now','needs_plan',NULL,370,'2026-04-15T18:37:49',NULL);
INSERT INTO plans VALUES(581,1,444,'Hook: auto-set plan status to verify on implementation complete','When Claude finishes implementing a plan item (all code written, build passes), the hook should automatically set the plan status to verify. Detect via ExitPlanMode or plan completion signals. Prevents forgetting to transition to verify after implementation.',NULL,NULL,'now','needs_plan',NULL,380,'2026-04-15T18:53:21',NULL);
INSERT INTO plans VALUES(582,1,444,'Hook: capture AskUserQuestion Q&A as plan decisions','On PostToolUse for AskUserQuestion, parse questions and answers from the event data and store them linked to the active plan item (via session active_goal_id). New table plan_decisions or similar, with question text, answer text, plan_id, timestamp. Multiple Q&A rounds for the same plan item should be stored as separate records. Enables reviewing design decisions made during implementation.',NULL,NULL,'now','needs_plan',NULL,390,'2026-04-16T02:02:32',NULL);
INSERT INTO plans VALUES(583,1,444,'CLI: endless plan show --status filter','Add a --status flag to ''endless plan show'' that filters the tree to items matching the given status (plus ancestors for tree context). Example: ''endless plan show --status in_progress'' shows only in-progress items and their parent chain.',NULL,NULL,'now','needs_plan',NULL,400,'2026-04-16T04:22:30',NULL);
INSERT INTO plans VALUES(587,1,444,'CLI: plan chat prints session ID','When ''endless plan chat'' starts a session, print the session ID so users can reference it later in plan items or commit messages. Currently just says ''Chat session started'' with no identifier.',NULL,NULL,'now','needs_plan',NULL,410,'2026-04-16T04:46:37',NULL);
INSERT INTO plans VALUES(588,1,444,'CLI: endless plan link <plan_id>','Associate the current active chat session with a plan item retroactively. Looks up current session (same mechanism as plan start), updates session active_goal_id to point at the plan item, optionally sets plan status to in_progress if still ready/needs_plan. Enables workflow: start chatting, realize work maps to a plan item, link without restarting session.',NULL,NULL,'now','needs_plan',NULL,420,'2026-04-16T04:46:37',NULL);
