INSERT INTO plans VALUES(599,1,596,'How is feedback triaged? (Dashboard widget? CLI command? Auto-categorized?)','How is feedback triaged? (Dashboard widget? CLI command? Auto-categorized?)',NULL,NULL,'now','needs_plan','/Users/mikeschinkel/.claude/plans/mutable-sprouting-thunder.md',10,'2026-04-16T04:54:53',NULL);
INSERT INTO plans VALUES(600,1,596,'Hook-based capture as a later enhancement, not primary mechanism','Hook-based capture as a later enhancement, not primary mechanism',NULL,NULL,'now','needs_plan','/Users/mikeschinkel/.claude/plans/mutable-sprouting-thunder.md',11,'2026-04-16T04:54:53',NULL);
INSERT INTO plans VALUES(601,1,590,'3. Remote feedback API (separate, future)','3. Remote feedback API (separate, future)',NULL,NULL,'later','needs_plan','/Users/mikeschinkel/.claude/plans/mutable-sprouting-thunder.md',12,'2026-04-16T04:54:53',NULL);
INSERT INTO plans VALUES(602,1,444,'Discussion: Notes vs. Feedback — clarify purpose of each','The notes system exists but its purpose is fuzzy. Agent feedback has an obvious value proposition. Resolve: What are notes FOR? Is agent feedback a different concern? Should notes be repurposed or eliminated? Could feedback + plan items cover all note use cases?',unistr('# Discussion: Agent Feedback Feature vs. Notes System\u000a\u000a## Context\u000a\u000aWhile dogfooding Endless across projects, agents naturally discover friction, missing features, and improvement ideas. Currently this requires the user to manually relay feedback between sessions — exactly the kind of cross-session coordination burden Endless exists to eliminate.\u000a\u000aThis raised a deeper question: what is the notes system actually for, and does a dedicated feedback feature better serve the use case of agents reporting back about Endless?\u000a\u000a## Plan Items to Create\u000a\u000a### 1. Discussion: Notes vs. Feedback — clarify purpose of each\u000a\u000aThe notes system exists but its purpose is fuzzy. Feedback from agents has an obvious value proposition. Questions to resolve:\u000a\u000a- What are notes FOR? (Document staleness alerts? User reminders? General annotations?)\u000a- Is "agent feedback about a tool" a fundamentally different thing from a "project note"?\u000a- Should notes be repurposed as the feedback mechanism, or are they separate concerns?\u000a- Could notes be eliminated entirely if feedback + plan items cover the use cases?\u000a\u000a### 2. Agent feedback feature (local, CLI-driven)\u000a\u000aA command like `endless feedback "message"` that any session on any project can run to submit a suggestion/bug/friction report back to Endless. Stored in the Endless DB, surfaced in the dashboard. The agent doesn''t need to know the internals — just run the command.\u000a\u000aOpen questions:\u000a- Where does feedback land? A `feedback` table? Notes on the endless project? Auto-created plan items?\u000a- Should feedback be tied to the session/project it came from?\u000a- How is feedback triaged? (Dashboard widget? CLI command? Auto-categorized?)\u000a- Hook-based capture as a later enhancement, not primary mechanism\u000a\u000a### 3. Remote feedback API (separate, future)\u000a\u000aFor multi-user scenarios: agents on other users'' machines could POST feedback to a central API (with user approval). This is architecturally different from local SQLite — it''s an API endpoint, likely on a hosted service. Separate plan from the local feedback feature.\u000a'),NULL,'now','needs_plan',NULL,430,'2026-04-16T04:56:24',NULL);
INSERT INTO plans VALUES(603,1,444,'Agent feedback feature (local, CLI-driven)','A command like ''endless feedback "message"'' that any session on any project can run to report friction/suggestions/bugs back to Endless. Open questions: storage mechanism, session/project attribution, triage/surfacing, hook capture as later enhancement.',NULL,NULL,'now','needs_plan',NULL,440,'2026-04-16T04:56:24',NULL);
INSERT INTO plans VALUES(604,1,444,'Remote feedback API (multi-user, future)','For multi-user scenarios: agents POST feedback to a central API with user approval. Architecturally separate from local SQLite — an API endpoint on a hosted service. Separate from local feedback feature.',NULL,NULL,'later','needs_plan',NULL,22,'2026-04-16T04:56:24',NULL);
INSERT INTO plans VALUES(616,1,444,'Plan text lifecycle: sync text after implementation','Define when and how plan text gets updated: after implementation to reflect what was actually done, after verify feedback, after completion. Currently plan text is written before implementation and never updated. Need a process (manual or automated) to keep plan text as living documentation rather than stale intent.',unistr('# Plan #616: Plan Text Lifecycle — Sync Text After Implementation\u000a\u000a## Context\u000a\u000aPlan text is written before implementation and never updated. By the time a plan item is completed, the text may be significantly diverged from what was actually built — decisions made during verify cycles, user feedback, changed approaches. The #510 implementation is a case study: the original plan proposed click-timers and templUI components, but the final implementation used overlay modals with plain HTML.\u000a\u000a## Proposed Approach\u000a\u000a### Structure: Original Plan + Implementation Record\u000a\u000aWhen a plan item is completed, its text should contain both the original intent and the actual outcome:\u000a\u000a```markdown\u000a# Plan #NNN: Title\u000a\u000a## Original Plan\u000a(the text as it was when status moved to `ready` or `in_progress`)\u000a\u000a## Implementation Record\u000a### What was built\u000a(summary of actual implementation)\u000a\u000a### Key decisions made during implementation\u000a(what changed from the plan and why — especially user feedback that redirected the approach)\u000a\u000a### Files modified\u000a(list of changed files)\u000a```\u000a\u000a### Mechanism\u000a\u000a**Option A: `plan complete` command appends** — When `endless plan complete <id>` is run, it prompts the session to provide implementation notes (or the session proactively provides them). The command prepends "## Original Plan" to the existing text and appends the new section.\u000a\u000a**Option B: Hook on status change** — The PostToolUse hook detects when `plan complete` is run and injects additionalContext asking the session to update the plan text via `endless plan update <id> --text <file>`.\u000a\u000a**Option C: Session guide convention** — The guide doc instructs sessions to update plan text before marking verify/complete. No automation, just convention.\u000a\u000a### Recommendation\u000a\u000aStart with **Option C** (add to guide doc now, zero code) and build toward **Option A** (automate in `plan complete`). Option B is fragile and over-engineered.\u000a\u000a### What to capture\u000a\u000a- Decisions that diverged from the original plan\u000a- User feedback that changed direction (especially from AskUserQuestion — ties to #582)\u000a- Files actually modified\u000a- Status transitions that happened (verify → in_progress → verify → completed)\u000a\u000a### Open questions\u000a\u000a- Should the original plan text be preserved verbatim, or can it be summarized?\u000a- Should `plan complete` refuse to complete if text hasn''t been updated since `in_progress`?\u000a- How does this interact with the audit trail (#617)?\u000a'),NULL,'now','needs_plan',NULL,450,'2026-04-16T05:28:46',NULL);
INSERT INTO plans VALUES(617,1,444,'Audit trail for plan changes','Track changes to plan items over time — who changed what, when, and why. Consider: git-based tracking (plan text is text), DB-level change log table, or hybrid. Important for accountability when working for others. Related to plan text history concern.',NULL,NULL,'next','needs_plan',NULL,10,'2026-04-16T05:28:46',NULL);
INSERT INTO plans VALUES(621,1,516,'Refactor inline JS to x-data methods in templ files','Move complex JavaScript from inline x-on attributes into named Alpine methods in x-data objects. For shared tree state (status page), use a Go helper function to build the x-data string. For per-item state (plan detail page), define methods in the per-item x-data. Inline handlers should be short method calls like saveEdit(id), not multi-statement chains. Completed as part of #510 implementation.',NULL,NULL,'now','completed',NULL,460,'2026-04-16T06:00:12','2026-04-16T06:00:12');
INSERT INTO plans VALUES(622,1,444,'CLI: endless quick-start command','Command that outputs (or writes to file) the session onboarding guide. Could dump to stdout for piping, or write a customizable file. Replaces manually sharing the guide doc. Consider: should it be context-aware (include project-specific plan tree)? Should it generate a file the user can edit and re-use?',NULL,NULL,'now','needs_plan',NULL,470,'2026-04-16T06:30:40',NULL);
INSERT INTO plans VALUES(623,1,444,'Discussion: parent/child projects and project vs. plan distinction','Sub-projects (CLI for a Go pkg, TUI testing, etc.) need a way to relate to parent projects. Options: parent_id on projects table, or a dep_type=''contains'' in project_deps. Deeper question: is the project/plan distinction legitimate? Projects = codebases (path, git, language, persistent). Plans = units of work (lifecycle, prompt, consumed). The asymmetry (plans need projects, projects don''t need plans) suggests they are genuinely different. But sub-project use cases blur the line. Resolve before adding more project hierarchy.',unistr('# Discussion: Parent/Child Projects and Project vs. Plan Distinction\u000a\u000a## Resolution\u000a\u000aThe sub-project concern turned out to be a same-repo, different-concerns scenario — not separate codebases. The right model is **plan tree branches within one project**, not parent/child projects.\u000a\u000a### Project vs. Plan — the distinction is real\u000a\u000a| Dimension | Project | Plan |\u000a|---|---|---|\u000a| **Identity** | A codebase (path, git, language) | A unit of work (lifecycle, prompt) |\u000a| **Persistence** | Permanent until unregistered | Temporary — completed and done |\u000a| **Ownership** | You own the codebase | A session works the plan |\u000a| **Hierarchy** | Grouping/dependencies between repos | Parent/child decomposition of work |\u000a| **Multiplicity** | One project = one directory | One project has many plans |\u000a\u000aMerging them into one table would put "go-tealeaves" (a codebase) and "Fix CLI flag parsing" (a task) as siblings, which is confusing.\u000a\u000a### Multiple concurrent sessions per project\u000a\u000aAlready supported. `ai_sessions.UNIQUE` is on `session_id`, not `project_id`. Multiple Claude sessions can each `plan start` a different plan branch in the same project. Created #624 for UI improvements to make this visible.\u000a\u000a### When separate projects ARE needed\u000a\u000aIf a CLI wrapper lives in its own repo with its own `go.mod`, it''s a separate project. The `group_name` field (already in schema) can group related projects. Full parent_id hierarchy is deferred unless grouping proves insufficient.\u000a\u000a## Status: Resolved — no schema changes needed\u000a'),NULL,'now','completed',NULL,480,'2026-04-16T06:30:40','2026-04-16T08:15:40');
INSERT INTO plans VALUES(624,1,444,'Multi-session support: show active sessions on plan items','plan show should indicate which items have active sessions working on them. plan start should warn (not block) if another session is already on the same item. Guide doc should explain the multi-session/plan-branch pattern for concurrent work on the same project.',NULL,NULL,'now','needs_plan',NULL,490,'2026-04-16T08:15:24',NULL);
INSERT INTO plans VALUES(625,1,444,'Project data export/import with schema versioning','Build proper endless export/import commands. Export writes project-scoped data (projects, plans, notes, deps) to .endless/data.sql with schema version header. Import restores from that file. Requires: schema version tracking (pre-v1.0 SemVer), migration system (evaluate migration tools vs hand-rolled), breaking vs non-breaking change distinction. Current db-export justfile recipe is a stopgap.',NULL,NULL,'now','needs_plan',NULL,500,'2026-04-16T08:56:38',NULL);
INSERT INTO plans VALUES(626,1,444,'Project role type: contrib projects with auto-exclude','Add a ''role'' field to projects: ''owner'' (default, it''s mine), ''contrib'' (PR/fork work on someone else''s repo), ''vendor'' (patching a dependency). Role drives behavior: contrib auto-adds .endless/ to .git/info/exclude on register, may affect enforcement level and dashboard grouping. Role is independent of status (a contrib project can be active/paused/etc). After implementation, set h2pp role=contrib.',NULL,NULL,'now','needs_plan',NULL,510,'2026-04-16T09:52:28',NULL);
INSERT INTO plans VALUES(634,1,444,'Tighten plan chat: require justification or remove','plan chat is a loophole that lets sessions bypass intent declaration entirely. Sessions use it to avoid picking a plan item. Options: remove it, require --reason flag, make it time-limited with nag to plan link, or have the hook inject context telling the session to ask the user which plan item to work on instead of defaulting to chat. The guide doc says to use plan start but sessions ignore it when plan chat exists as an easy out.',NULL,NULL,'now','needs_plan',NULL,520,'2026-04-17T06:37:06',NULL);
INSERT INTO plans VALUES(640,1,516,'Show relative priority number next to plan titles','Display a sibling-scoped priority number (1, 2, 3...) between the status sphere and title. Numbers reset per parent, reflect current sort order (ephemeral, not stored). Fixed-width column (w-6 text-center) for alignment. Dim cyan color for readability. Sets up visual language for drag-and-drop reorder (#508).',NULL,NULL,'now','completed',NULL,530,'2026-04-17T06:48:16','2026-04-17T07:03:20');
INSERT INTO plans VALUES(686,1,516,'Add a "needs-attention" flat list section above plan tree','A flat list above the tree showing items needing action (verify, blocked) regardless of hierarchy position. Like an inbox for the plan tree. Each entry shows #ID, title, and status. Clicking an entry expands the parent chain and scrolls to the item in the tree. Always visible, zero interaction needed to scan. Solves: finding what to verify without expanding every branch.',NULL,NULL,'now','needs_plan',NULL,540,'2026-04-17T07:05:59',NULL);
INSERT INTO plans VALUES(687,1,516,'Add child status indicators inline on collapsed parents','When a parent item is collapsed, show small muted counts to the right of the title like ''1 verify · 3 needs_plan''. Only visible when collapsed (x-show tied to open state). Gives at-a-glance summary of what is underneath without expanding. Solves: seeing status of top pending items when browsing collapsed tree.',NULL,NULL,'now','needs_plan',NULL,550,'2026-04-17T07:06:00',NULL);
INSERT INTO plans VALUES(696,1,444,'CLI: plan remove should cascade or warn about children','Currently plan remove on a parent orphans all children as top-level items. Should either cascade delete children by default (with confirmation), or warn and require --recursive flag. The h2pp session had to manually remove 44 orphaned items after removing a parent.',NULL,NULL,'now','needs_plan',NULL,560,'2026-04-17T19:06:11',NULL);
INSERT INTO plans VALUES(697,1,444,'Inter-session messaging: backchannel communication between Claude sessions','Enable two Claude Code sessions to exchange messages through Endless without human copy-paste. Architecture: channel table (beacon/connect pattern), message queue table, delivery via hook additionalContext. MVP requires tmux: when Session A sends a message, the hook uses tmux send-keys to inject a prompt into Session B''s pane, triggering UserPromptSubmit which picks up the queued message. Human stays in Session A — approves actions, sees replies. No terminal switching needed. MVP commands: endless msg beacon, endless msg connect, endless msg send. Later: replace tmux delivery with endless daemon (#698).',NULL,NULL,'next','in_progress',NULL,20,'2026-04-17T19:26:43',NULL);
INSERT INTO plans VALUES(698,1,444,'Endless daemon for active message delivery and background tasks','A long-running endless daemon process (separate from endless serve) that can actively push messages to sessions rather than waiting for hooks to pull. Would replace tmux-based message delivery for inter-session chat. Could also handle: scheduled plan status checks, dormancy detection, file change monitoring without ZSH hooks. Architectural shift from hook-driven (reactive) to daemon-driven (proactive). Post-MVP for inter-session messaging.',NULL,NULL,'later','needs_plan',NULL,32,'2026-04-17T19:35:55',NULL);
INSERT INTO plans VALUES(699,1,444,'Disambiguate plan item IDs from GitHub issue numbers','Sessions interpret #NNN as GitHub issues, not Endless plan items. Need either: a distinct prefix for plan IDs (P697, plan:697, etc.), clearer guide doc language, or both. Related question: should Endless plan items optionally map to GitHub issues? ID sync is hard (separate auto-increment sequences) but cross-referencing could be valuable. For now, fix the ambiguity so sessions don''t try to use gh CLI to look up plan items.',NULL,NULL,'now','needs_plan',NULL,570,'2026-04-17T22:51:37',NULL);
INSERT INTO plans VALUES(700,1,699,'Plan ID prefix convention','Prefix convention for Endless plan IDs: E-697 format. Three rules: (1) CLI args accept both 697 and E-697 when expecting a plan ID — strip prefix internally. (2) All output (CLI, web dashboard, guide doc) always displays E-NNN. (3) In conversation, E-697 means Endless, plain 697 is ambiguous — AI should ask for clarification not assume. Implementation: update plan show, plan detail, plan add output, web templates, guide doc. Similar to Git short-SHA pattern: input forgiving, output strict.',NULL,NULL,'now','completed',NULL,580,'2026-04-17T22:54:50','2026-04-17T23:06:40');
INSERT INTO plans VALUES(701,1,444,'Add notes field to plans table for post-completion annotations','Add a ''notes'' column (TEXT, nullable) to the plans table for post-implementation observations: bugfixes, lessons, decisions made after the plan was written. Separate from ''text'' (the plan) and ''description'' (short summary). Update CLI: ''plan update --notes'' to append (not replace). Update ''plan detail'' to display notes section. Update web detail pane to show notes. NOT the same as the notes system (project-level notes table).',NULL,NULL,'now','needs_plan',NULL,590,'2026-04-17T23:12:29',NULL);
INSERT INTO plans VALUES(702,1,444,'Project discussion log: capture decisions and reasoning via hook','Log substantive discussions (not raw tool calls) linked to projects and plan items. Goal: answer ''what did we decide about X?'' without re-reading full transcripts. May capture via hook on UserPromptSubmit (user messages) and Stop (assistant summaries). Store in a discussion_log table with project_id, plan_id, timestamp, source (user/assistant), content. Related to E-582 (Q&A capture) but broader scope. Existing claude-log-hook captures tool calls, not conversations. Claude transcripts exist but aren''t indexed or searchable by project/plan.',NULL,NULL,'next','needs_plan',NULL,30,'2026-04-17T23:14:50',NULL);
INSERT INTO plans VALUES(703,1,516,'Toggle plan IDs always-visible vs hover-only','Add a toggle button in the plan tree header (next to Expand/Collapse) that switches E-NNN IDs between hover-only (current) and always-visible. When visible, users can Cmd-F to find by ID. Simple Alpine boolean toggle. Cheapest solution to ''find item by ID'' problem.',NULL,NULL,'now','completed',NULL,600,'2026-04-17T23:34:05','2026-04-18T00:07:18');
INSERT INTO plans VALUES(704,1,516,'Plan tree filter system','Filter controls for the plan tree: by status, phase, keyword search, has-text, has-children. Filters apply to the tree preserving hierarchy (show matching items + ancestor chain). Most important scalability feature as plan count grows. Consider: filter bar below the header, pill-style active filters, clear-all button.',NULL,NULL,'now','needs_plan',NULL,610,'2026-04-17T23:34:05',NULL);
INSERT INTO plans VALUES(705,1,516,'Tree/flat view toggle with sort options','Toggle between tree view (current, hierarchy preserved) and flat list view (all items sorted). Flat view supports sort by: status priority, phase, title alpha, ID, created date. Tree view keeps current sort-by-status-within-siblings. Two views, one page.',NULL,NULL,'next','needs_plan',NULL,40,'2026-04-17T23:34:05',NULL);
INSERT INTO plans VALUES(706,1,516,'Design plan tree action bar (dedicated row for controls)','Current header row is getting crowded with Expand/Collapse/Full plan/IDs. Design a proper action bar as a dedicated second row below the PLAN header. Group controls logically: view switches (tree/flat), tree controls (expand/collapse), display toggles (IDs), filter controls. Needed before E-704 (filters) adds more controls. Consider options B and C from discussion.',NULL,NULL,'now','needs_plan',NULL,620,'2026-04-17T23:57:30',NULL);
INSERT INTO plans VALUES(707,1,444,'BUG: Stop event ends sessions between turns — breaks messaging','The hook''s Stop handler calls EndSession which sets state=ended. Between Claude turns, _resolve_session() can''t find an active session. This makes every msg command fail unless you re-run plan start. Stop should set state to ''idle'' not ''ended'', or use SessionEnd for actual end-of-conversation. Issue #2 from inter-session testing. Issue #7 (needing plan start before every msg) is a symptom.',NULL,NULL,'now','completed',NULL,630,'2026-04-18T00:11:12','2026-04-18T00:23:19');
INSERT INTO plans VALUES(708,1,444,'BUG: Hook swallows DB errors silently','Hook swallows DB errors silently with ''_ = monitor.SomeFunc()''. Also _tmux_nudge in channel_cmd.py uses capture_output=True which suppresses tmux errors. Need: (1) hook error logging to stderr or a log file (~/.config/endless/hook.log), (2) surface tmux nudge failures to user. Issue #4 from inter-session testing, plus nudge suppression reported in follow-up.',NULL,NULL,'now','needs_plan',NULL,640,'2026-04-18T00:11:12',NULL);
INSERT INTO plans VALUES(709,1,444,'BUG: Chained Bash commands race with PostToolUse hook','If plan start and msg beacon are chained in one Bash call (&&), PostToolUse fires after both commands complete. msg beacon fails because the session doesn''t exist yet (plan start detection hasn''t run). Commands must be separate Bash tool calls. Document in guide, consider fixing by processing commands eagerly. Issue #5 from inter-session testing.',NULL,NULL,'now','needs_plan',NULL,650,'2026-04-18T00:11:12',NULL);
INSERT INTO plans VALUES(710,1,444,'BUG: msg inbox doesn''t mark messages as delivered','Python inbox queries status=queued but doesn''t mark them delivered. Only Go GetPendingMessages marks delivery. Inbox keeps showing same messages. Either inbox should mark them, or show all with status indicators. Issue #6 from inter-session testing.',NULL,NULL,'now','completed',NULL,660,'2026-04-18T00:11:12','2026-04-18T00:42:57');
INSERT INTO plans VALUES(711,1,444,'Channel inbox: show message history with status indicators','Inbox currently only shows queued messages. Add option to show recent messages regardless of status (queued/delivered) with status indicators, so users can review conversation history. E.g. endless channel inbox --history',NULL,NULL,'next','needs_plan',NULL,50,'2026-04-18T00:46:14',NULL);
INSERT INTO plans VALUES(712,1,444,'Test endless channel close end-to-end','endless channel close exists but hasn''t been tested. Verify both sessions are notified, channel state transitions correctly, and subsequent send/inbox calls fail gracefully.',NULL,NULL,'now','needs_plan',NULL,670,'2026-04-18T00:46:14',NULL);
INSERT INTO plans VALUES(713,1,444,'Update session guide with inter-session messaging','Add a section to docs/guide-2026-04-15-using-endless-in-sessions.md covering the channel commands: beacon, connect, send, inbox, close, list. Include the master/slave workflow pattern.',NULL,NULL,'now','needs_plan',NULL,680,'2026-04-18T00:46:14',NULL);
INSERT INTO notes VALUES(6,1,'sprawl','Multiple readme files detected: .pytest_cache/README.md, README.md. Consider consolidating.','readme',NULL,0,'2026-04-08T19:43:08',NULL);
INSERT INTO task_dependencies VALUES(1,'task',510,'task',509,'needs','2026-04-15T18:30:28');
